import MaxWidthWrapper from "@/components/ui/max-width-wrapper";
import { techStack } from "@/lib/constants";
import { Marquee } from "../ui/marquee";

const Skills = () => {
  return (
    <MaxWidthWrapper parentBorder="border-b">
      <div className="relative flex w-full flex-col items-center justify-center overflow-hidden">
        <div className="w-full border-b border-border/50 px-6 py-4 flex items-center gap-3">
          <span className="inline-block w-2 h-2 rounded-full bg-emerald-500" />
          <span className="text-[11px] uppercase tracking-[3px] text-muted-foreground font-medium">
            Tech Stack
          </span>
        </div>
        <div className="relative w-full py-6">
          <Marquee>
            {techStack.map((skill) => (
              <span
                key={skill.name}
                className="mx-2.5 rounded-full border border-border/60 bg-muted/50 px-5 py-2.5 font-mono text-sm text-foreground whitespace-nowrap transition-all duration-300 hover:border-emerald-500/50 hover:bg-emerald-500/10 hover:scale-105 hover:shadow-[0_0_15px_rgba(16,185,129,0.15)] cursor-default"
              >
                {skill.name}
              </span>
            ))}
          </Marquee>
          <div className="from-background pointer-events-none absolute inset-y-0 left-0 w-1/4 bg-linear-to-r" />
          <div className="from-background pointer-events-none absolute inset-y-0 right-0 w-1/4 bg-linear-to-l" />
        </div>
      </div>
    </MaxWidthWrapper>
  );
};

export default Skills;
