import MaxWidthWrapper from "@/components/ui/max-width-wrapper";
import type { education } from "@/generated/prisma/client";
import { server } from "@/lib/elysia/server";

function EducationCard({ entry }: { entry: education }) {
  return (
    <div className="flex flex-col gap-1 rounded-xl border border-border bg-card p-5 shadow-sm transition-shadow duration-200 hover:shadow-md">
      <h3 className="font-mono text-base font-semibold text-foreground">
        {entry.institution}
      </h3>
      <p className="font-mono text-sm text-muted-foreground">
        {entry.degree}
        {entry.field && ` — ${entry.field}`}
      </p>
      {entry.graduationDate && (
        <span className="mt-1 w-fit rounded border border-border/60 bg-muted/50 px-2 py-0.5 font-mono text-xs text-muted-foreground">
          {entry.graduationDate}
        </span>
      )}
    </div>
  );
}

const Education = async () => {
  const res = await server.education.get();
  const rawEducation = Array.isArray(res)
    ? res
    : (res as { data?: education[] })?.data;
  const educationList = rawEducation ?? [];

  return (
    <section id="education" className="scroll-mt-20">
      <MaxWidthWrapper parentBorder="border-b">
        <div className="flex flex-col gap-2 p-5 border-b">
          <span className="text-xs font-semibold uppercase tracking-[4px] text-primary">Academic Background</span>
          <h2 className="font-display text-3xl font-light tracking-tight text-foreground">Education</h2>
        </div>
        <div className="grid w-full grid-cols-1 gap-5 p-5 md:grid-cols-2">
          {educationList.map((entry) => (
            <EducationCard key={entry.id} entry={entry} />
          ))}
        </div>
      </MaxWidthWrapper>
    </section>
  );
};

export default Education;
